import React, { useState, useEffect, useRef } from 'react';
import axios from 'axios';
import './App.css';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

function App() {
  const [notes, setNotes] = useState([]);
  const [currentNote, setCurrentNote] = useState({
    title: '',
    content: '',
    category: 'General',
    source: 'text'
  });
  const [isListening, setIsListening] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [editingId, setEditingId] = useState(null);
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [isRecordingScreen, setIsRecordingScreen] = useState(false);
  const [videoFile, setVideoFile] = useState(null);
  const [isProcessingVideo, setIsProcessingVideo] = useState(false);
  const [videoProgress, setVideoProgress] = useState('');
  const [activeTab, setActiveTab] = useState('text');
  const [isGeneratingSummary, setIsGeneratingSummary] = useState(false);
  const [viewingNote, setViewingNote] = useState(null);
  const [translatedContent, setTranslatedContent] = useState({});
  const [isTranslating, setIsTranslating] = useState(false);
  const [showChat, setShowChat] = useState(false);
  const [chatMessages, setChatMessages] = useState([]);
  const [chatInput, setChatInput] = useState('');
  const [isAIThinking, setIsAIThinking] = useState(false);
  const [loading, setLoading] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(true);

  const recognitionRef = useRef(null);
  const synthRef = useRef(window.speechSynthesis);
  const screenStreamRef = useRef(null);

  const categories = [
    'General', 'Math', 'Science', 'History',
    'Literature', 'Programming', 'Languages', 'Other'
  ];

  // ================= SPEECH RECOGNITION =================
  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
      const SpeechRecognition =
        window.SpeechRecognition || window.webkitSpeechRecognition;

      const recognition = new SpeechRecognition();
      recognition.continuous = true;
      recognition.interimResults = true;

      recognition.onresult = (event) => {
        let finalTranscript = '';
        for (let i = event.resultIndex; i < event.results.length; i++) {
          if (event.results[i].isFinal) {
            finalTranscript += event.results[i][0].transcript + ' ';
          }
        }
        if (finalTranscript) {
          setCurrentNote(prev => ({
            ...prev,
            content: prev.content + finalTranscript
          }));
        }
      };

      recognition.onerror = (e) => {
        setError(`Speech error: ${e.error}`);
        setIsListening(false);
      };

      recognition.onend = () => setIsListening(false);

      recognitionRef.current = recognition;
    }
  }, []);

  useEffect(() => {
    return () => synthRef.current.cancel();
  }, []);

  useEffect(() => {
    fetchNotes();
  }, [selectedCategory, searchQuery]);

  useEffect(() => {
    if (error || success) {
      const timer = setTimeout(() => {
        setError('');
        setSuccess('');
      }, 4000);
      return () => clearTimeout(timer);
    }
  }, [error, success]);

  const stopAllRecording = () => {
    recognitionRef.current?.stop();
    screenStreamRef.current?.getTracks().forEach(track => track.stop());
    setIsListening(false);
    setIsRecordingScreen(false);
    setVideoProgress('');
  };

  const fetchNotes = async () => {
    try {
      setLoading(true);
      const params = new URLSearchParams();
      if (selectedCategory !== 'All') params.append('category', selectedCategory);
      if (searchQuery) params.append('search', searchQuery);

      const res = await axios.get(`${API_URL}/notes?${params}`);
      setNotes(res.data);
    } catch {
      setError('Failed to fetch notes');
    } finally {
      setLoading(false);
    }
  };

  const askAIAboutNotes = async () => {
    if (!chatInput.trim()) return;

    setChatMessages(prev => [...prev, { role: 'user', content: chatInput }]);
    setChatInput('');
    setIsAIThinking(true);

    try {
      const res = await axios.post(`${API_URL}/chat`, {
        question: chatInput,
        allNotes: viewingNote ? [viewingNote] : notes
      });

      setChatMessages(prev => [
        ...prev,
        { role: 'assistant', content: res.data.response }
      ]);
    } catch {
      setError('AI chat failed');
    } finally {
      setIsAIThinking(false);
    }
  };

  const generateSmartNotes = async () => {
    if (!currentNote.content) {
      setError('Please add content first');
      return;
    }
    setIsGeneratingSummary(true);

    try {
      const res = await axios.post(`${API_URL}/generate-summary`, {
        content: currentNote.content
      });

      const summary = res.data.summary || res.data.result?.summary || 'Summary not available';
      const keywords = res.data.keywords || res.data.result?.keywords || [];

      const smartText = `📌 SUMMARY:\n${summary}\n\n🔑 KEYWORDS:\n${keywords.length ? keywords.join(', ') : 'No keywords'}\n\n📝 ORIGINAL CONTENT:\n${currentNote.content}`;

      setCurrentNote(prev => ({ ...prev, content: smartText }));
      setSuccess('Smart summary generated!');
    } catch {
      setError('Summary generation failed');
    } finally {
      setIsGeneratingSummary(false);
    }
  };

  const toggleListening = () => {
    if (!recognitionRef.current) {
      setError('Speech recognition not supported');
      return;
    }

    if (isListening) {
      stopAllRecording();
    } else {
      stopAllRecording();
      recognitionRef.current.start();
      setIsListening(true);
      setCurrentNote(prev => ({ ...prev, source: 'voice' }));
    }
  };

  const startScreenRecording = async () => {
    stopAllRecording();
    try {
      const stream = await navigator.mediaDevices.getDisplayMedia({
        video: true,
        audio: true
      });

      screenStreamRef.current = stream;
      recognitionRef.current.start();
      setIsRecordingScreen(true);
      setVideoProgress('Recording screen...');

      stream.getVideoTracks()[0].onended = stopScreenRecording;
    } catch (e) {
      setError(e.message);
    }
  };

  const stopScreenRecording = () => {
    screenStreamRef.current?.getTracks().forEach(t => t.stop());
    recognitionRef.current.stop();
    setIsRecordingScreen(false);
    setVideoProgress('');
    setSuccess('Screen recording completed!');
  };

  const handleVideoUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    setVideoFile(file);
    setIsProcessingVideo(true);

    const formData = new FormData();
    formData.append('video', file);

    try {
      await axios.post(`${API_URL}/upload-video`, formData);
      setCurrentNote(prev => ({
        ...prev,
        content: prev.content + `\n[Video Uploaded: ${file.name}]`,
        source: 'video'
      }));
      setSuccess('Video uploaded');
    } catch {
      setError('Video upload failed');
    } finally {
      setIsProcessingVideo(false);
    }
  };

  const speakText = (text) => {
    if (!text) return;

    if (isSpeaking) {
      synthRef.current.cancel();
      setIsSpeaking(false);
      return;
    }

    const utter = new SpeechSynthesisUtterance(text);
    utter.onstart = () => setIsSpeaking(true);
    utter.onend = () => setIsSpeaking(false);

    synthRef.current.speak(utter);
  };

  const saveNote = async () => {
    if (!currentNote.title || !currentNote.content) {
      setError('Title and content required');
      return;
    }

    try {
      editingId
        ? await axios.put(`${API_URL}/notes/${editingId}`, currentNote)
        : await axios.post(`${API_URL}/notes`, currentNote);

      setSuccess(editingId ? 'Note updated!' : 'Note saved!');
      setCurrentNote({ title: '', content: '', category: 'General', source: 'text' });
      setEditingId(null);
      fetchNotes();
    } catch {
      setError('Save failed');
    }
  };

  const deleteNote = async (id) => {
    if (!window.confirm('Delete this note?')) return;
    try {
      await axios.delete(`${API_URL}/notes/${id}`);
      setSuccess('Note deleted');
      fetchNotes();
    } catch {
      setError('Delete failed');
    }
  };

  const editNote = (note) => {
    setCurrentNote({
      title: note.title,
      content: note.content,
      category: note.category,
      source: note.source
    });
    setEditingId(note._id);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const downloadNote = (note) => {
    const blob = new Blob([note.content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${note.title}.txt`;
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="app-container">
      {/* Sidebar */}
      <aside className={`sidebar ${sidebarOpen ? 'open' : 'closed'}`}>
        <div className="sidebar-header">
          <h2>📚 Notes</h2>
          <button 
            className="toggle-sidebar"
            onClick={() => setSidebarOpen(!sidebarOpen)}
          >
            {sidebarOpen ? '◀' : '▶'}
          </button>
        </div>

        <div className="search-box">
          <input
            type="text"
            placeholder="🔍 Search notes..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
        </div>

        <div className="category-filter">
          <label>Filter by Category:</label>
          <select 
            value={selectedCategory}
            onChange={(e) => setSelectedCategory(e.target.value)}
          >
            <option value="All">All Categories</option>
            {categories.map(cat => (
              <option key={cat} value={cat}>{cat}</option>
            ))}
          </select>
        </div>

        <div className="notes-list">
          {loading ? (
            <div className="loading">Loading...</div>
          ) : notes.length === 0 ? (
            <div className="no-notes">No notes yet. Create your first note!</div>
          ) : (
            notes.map(note => (
              <div key={note._id} className="note-item">
                <div className="note-item-header">
                  <h4>{note.title}</h4>
                  <span className="note-category">{note.category}</span>
                </div>
                <p className="note-preview">
                  {note.content.substring(0, 80)}...
                </p>
                <div className="note-item-actions">
                  <button onClick={() => editNote(note)} className="btn-sm btn-edit">
                    ✏️ Edit
                  </button>
                  <button onClick={() => setViewingNote(note)} className="btn-sm btn-view">
                    👁️ View
                  </button>
                  <button onClick={() => downloadNote(note)} className="btn-sm btn-download">
                    ⬇️
                  </button>
                  <button onClick={() => deleteNote(note._id)} className="btn-sm btn-delete">
                    🗑️
                  </button>
                </div>
              </div>
            ))
          )}
        </div>
      </aside>

      {/* Main Content */}
      <main className="main-content">
        <header className="app-header">
          <h1>✨ Smart Note-Taking Assistant</h1>
          <p className="subtitle">Capture ideas with text, voice, video, or screen recording</p>
        </header>

        {/* Alerts */}
        {error && (
          <div className="alert alert-error">
            <span>⚠️ {error}</span>
            <button onClick={() => setError('')}>✕</button>
          </div>
        )}
        {success && (
          <div className="alert alert-success">
            <span>✓ {success}</span>
            <button onClick={() => setSuccess('')}>✕</button>
          </div>
        )}

        {/* Note Editor */}
        <div className="note-editor">
          <div className="editor-header">
            <input
              type="text"
              className="title-input"
              placeholder="📝 Note Title..."
              value={currentNote.title}
              onChange={e => setCurrentNote({ ...currentNote, title: e.target.value })}
            />
            <select
              className="category-select"
              value={currentNote.category}
              onChange={e => setCurrentNote({ ...currentNote, category: e.target.value })}
            >
              {categories.map(cat => (
                <option key={cat} value={cat}>{cat}</option>
              ))}
            </select>
          </div>

          {/* Input Mode Tabs */}
          <div className="mode-tabs">
            <button
              className={`mode-tab ${activeTab === 'text' ? 'active' : ''}`}
              onClick={() => setActiveTab('text')}
            >
              <span className="icon">✍️</span>
              <span>Text</span>
            </button>
            <button
              className={`mode-tab ${activeTab === 'voice' ? 'active' : ''}`}
              onClick={() => setActiveTab('voice')}
            >
              <span className="icon">🎤</span>
              <span>Voice</span>
            </button>
            <button
              className={`mode-tab ${activeTab === 'video' ? 'active' : ''}`}
              onClick={() => setActiveTab('video')}
            >
              <span className="icon">🎥</span>
              <span>Video</span>
            </button>
            <button
              className={`mode-tab ${activeTab === 'screen' ? 'active' : ''}`}
              onClick={() => setActiveTab('screen')}
            >
              <span className="icon">🖥️</span>
              <span>Screen</span>
            </button>
          </div>

          {/* Content Area */}
          <div className="content-area">
            {activeTab === 'text' && (
              <textarea
                className="content-textarea"
                placeholder="Start typing your notes here..."
                rows="12"
                value={currentNote.content}
                onChange={e => setCurrentNote({ ...currentNote, content: e.target.value })}
              />
            )}

            {activeTab === 'voice' && (
              <div className="voice-mode">
                <button 
                  className={`voice-button ${isListening ? 'listening' : ''}`}
                  onClick={toggleListening}
                >
                  <span className="pulse-ring"></span>
                  {isListening ? '⏹ Stop Listening' : '🎤 Start Voice Input'}
                </button>
                <textarea
                  className="content-textarea"
                  placeholder="Voice input will appear here..."
                  rows="12"
                  value={currentNote.content}
                  readOnly
                />
              </div>
            )}

            {activeTab === 'video' && (
              <div className="video-mode">
                <label className="file-upload">
                  <input 
                    type="file" 
                    accept="video/*" 
                    onChange={handleVideoUpload}
                    hidden
                  />
                  <span className="upload-icon">📹</span>
                  <span>Click to upload video</span>
                </label>
                {isProcessingVideo && (
                  <div className="processing">
                    <div className="spinner"></div>
                    <p>Processing video...</p>
                  </div>
                )}
                {videoFile && (
                  <div className="file-info">
                    ✅ {videoFile.name}
                  </div>
                )}
              </div>
            )}

            {activeTab === 'screen' && (
              <div className="screen-mode">
                {!isRecordingScreen ? (
                  <button 
                    className="screen-button"
                    onClick={startScreenRecording}
                  >
                    <span className="icon">🖥️</span>
                    Start Screen Recording
                  </button>
                ) : (
                  <button 
                    className="screen-button recording"
                    onClick={stopScreenRecording}
                  >
                    <span className="recording-dot"></span>
                    Stop Recording
                  </button>
                )}
                {videoProgress && <p className="progress-text">{videoProgress}</p>}
              </div>
            )}
          </div>

          {/* Action Buttons */}
          <div className="action-buttons">
            <button 
              className="btn btn-secondary"
              onClick={() => speakText(currentNote.content)}
              disabled={!currentNote.content}
            >
              {isSpeaking ? '⏹ Stop' : '🔊 Read Aloud'}
            </button>
            <button 
              className="btn btn-secondary"
              onClick={generateSmartNotes}
              disabled={!currentNote.content || isGeneratingSummary}
            >
              {isGeneratingSummary ? '⏳ Generating...' : '✨ Smart Summary'}
            </button>
            <button 
              className="btn btn-primary"
              onClick={saveNote}
            >
              💾 {editingId ? 'Update Note' : 'Save Note'}
            </button>
            {editingId && (
              <button 
                className="btn btn-secondary"
                onClick={() => {
                  setEditingId(null);
                  setCurrentNote({ title: '', content: '', category: 'General', source: 'text' });
                }}
              >
                Cancel
              </button>
            )}
          </div>
        </div>

        {/* AI Chat Toggle */}
        <button 
          className="chat-toggle"
          onClick={() => setShowChat(!showChat)}
        >
          💬 AI Assistant
        </button>

        {/* AI Chat Panel */}
        {showChat && (
          <div className="chat-panel">
            <div className="chat-header">
              <h3>🤖 AI Assistant</h3>
              <button onClick={() => setShowChat(false)}>✕</button>
            </div>
            <div className="chat-messages">
              {chatMessages.length === 0 ? (
                <div className="chat-empty">
                  Ask me anything about your notes!
                </div>
              ) : (
                chatMessages.map((msg, i) => (
                  <div key={i} className={`chat-message ${msg.role}`}>
                    <div className="message-content">{msg.content}</div>
                  </div>
                ))
              )}
              {isAIThinking && (
                <div className="chat-message assistant thinking">
                  <div className="typing-indicator">
                    <span></span><span></span><span></span>
                  </div>
                </div>
              )}
            </div>
            <div className="chat-input-area">
              <input
                type="text"
                placeholder="Ask about your notes..."
                value={chatInput}
                onChange={e => setChatInput(e.target.value)}
                onKeyPress={e => e.key === 'Enter' && askAIAboutNotes()}
              />
              <button onClick={askAIAboutNotes}>Send</button>
            </div>
          </div>
        )}
      </main>

      {/* Note Viewer Modal */}
      {viewingNote && (
        <div className="modal-overlay" onClick={() => setViewingNote(null)}>
          <div className="modal-content" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h2>{viewingNote.title}</h2>
              <button onClick={() => setViewingNote(null)}>✕</button>
            </div>
            <div className="modal-body">
              <div className="note-meta">
                <span className="badge">{viewingNote.category}</span>
                <span className="badge">{viewingNote.source}</span>
              </div>
              <div className="note-content">
                {viewingNote.content}
              </div>
            </div>
            <div className="modal-footer">
              <button onClick={() => speakText(viewingNote.content)}>
                🔊 Read Aloud
              </button>
              <button onClick={() => downloadNote(viewingNote)}>
                ⬇️ Download
              </button>
              <button onClick={() => {
                editNote(viewingNote);
                setViewingNote(null);
              }}>
                ✏️ Edit
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;
